const fs = require('fs');
const path = require('path');
const { buildSeedRows } = require('../backend/lib/catalog-seed-data');

const METAL_DISPLAY_ORDER = ['9k', '14k', '18k', 'pt950', 's925'];
const CATEGORY_DISPLAY_ORDER = ['pendant', 'ring', 'earring', 'bracelet', 'chain'];

function sortGolds(golds) {
  const order = Object.fromEntries(METAL_DISPLAY_ORDER.map((g, i) => [g, i]));
  return [...golds].sort((a, b) => (order[a] ?? 99) - (order[b] ?? 99));
}

function imageUrl(filePath) {
  if (!filePath) return '';
  if (filePath.startsWith('http://') || filePath.startsWith('https://')) return filePath;
  const rel = filePath.replace(/^\//, '');
  return '../../' + rel;
}

function buildCatalogProduct(row) {
  const golds = sortGolds([...new Set(row.variants.map((v) => v.gold))]);
  const carats = [...new Set(row.variants.map((v) => v.carat))].sort();
  const weights = {};
  for (const v of row.variants) {
    (weights[v.gold] ||= {})[v.carat] = v.weightChin;
  }
  const imagesByColor = {};
  for (const img of row.images) {
    (imagesByColor[img.color] ||= []).push(imageUrl(img.filePath));
  }
  return {
    id: `${row.category}-${row.style}`,
    nameZh: row.nameZh,
    nameEn: null,
    descriptionZh: null,
    descriptionEn: null,
    defaultColor: row.defaultColor,
    golds,
    carats,
    colors: Object.keys(imagesByColor).sort(),
    images: imagesByColor,
    weights,
    manualPrices: {},
    draft: false,
  };
}

const categories = {};
for (const row of buildSeedRows()) {
  const product = buildCatalogProduct(row);
  (categories[row.category] ||= []).push(product);
}
for (const list of Object.values(categories)) {
  list.sort((a, b) => a.id.localeCompare(b.id));
}

const present = Object.keys(categories);
const categoryOrder = CATEGORY_DISPLAY_ORDER.filter((c) => present.includes(c))
  .concat(present.filter((c) => !CATEGORY_DISPLAY_ORDER.includes(c)));

const payload = { categories, categoryOrder };
const out = `/* Static shop catalog — generated by scripts/build-shop-catalog-static.cjs */
(function (global) {
  'use strict';
  global.shopCatalogData = ${JSON.stringify(payload, null, 2)};
})(window);
`;

const outPath = path.join(__dirname, '..', 'app', 'static', 'js', 'shop-catalog-data.js');
fs.writeFileSync(outPath, out);
console.log('Wrote', outPath, `(${Object.values(categories).flat().length} products)`);
